sys_script_include.script:
var LinqQRHelper = Class.create();
LinqQRHelper.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {
    initialize: function() {},

    generateToken: function(studentSysId, eventSysId) {
        var gdt = new GlideDateTime();
        var raw = studentSysId + '_' + eventSysId + '_' + gdt.getNumericValue();
        var digest = new GlideDigest();
        return digest.getMD5Base64(raw);
    },

    validateToken: function(token) {
        if (!token) {
            token = this.getParameter('sysparm_token');
        }
        var gr = new GlideRecord('x_2097092_linq_registration');
        gr.addQuery('qr_token', token);
        gr.addQuery('status', 'registered');
        gr.query();
        if (gr.next()) {
            return JSON.stringify({
                valid: true,
                registrationId: gr.getUniqueValue(),
                studentName: gr.student.getDisplayValue(),
                eventName: gr.event.getDisplayValue()
            });
        }
        return JSON.stringify({
            valid: false,
            message: 'Invalid or already used QR code.'
        });
    },

    type: 'LinqQRHelper'
});
